1	// src/gateway.ts — Discord + LINE + Signal + webhooks + TUI
2	
3	import { Client, GatewayIntentBits, type TextChannel } from "discord.js";
4	import { messagingApi, middleware } from "@line/bot-sdk";
5	import express from "express";
6	import readline from "readline";
7	import { think, type Turn } from "./agent.js";
8	import { type MameConfig, type PersonaConfig, MAME_HOME } from "./config.js";
9	import { SignalClient, type SignalMessage } from "./signal.js";
10	import { runSignalOnboarding } from "./onboard.js";
11	import { Vault } from "./vault.js";
12	import { recall, listMemories, memoryStats } from "./memory.js";
13	import { childLogger } from "./logger.js";
14	import { provideAnswer, hasPendingQuestion } from "./ask-human-state.js";
15	import {
16	  exchangeCodeForTokens,
17	  storeTokens,
18	  readPendingAuth,
19	  clearPendingAuth,
20	} from "./x-auth.js";
21	
22	const log = childLogger("gateway");
23	
24	function splitMessage(text: string, maxLen: number): string[] {
25	  if (text.length <= maxLen) return [text];
26	  const chunks: string[] = [];
27	  let remaining = text;
28	  while (remaining.length > 0) {
29	    chunks.push(remaining.slice(0, maxLen));
30	    remaining = remaining.slice(maxLen);
31	  }
32	  return chunks;
33	}
34	
35	export class Gateway {
36	  private discord: Client | null = null;
37	  private line: messagingApi.MessagingApiClient | null = null;
38	  private signal: SignalClient | null = null;
39	  private webhookServer: express.Application;
40	  private config: MameConfig;
41	  private persona: PersonaConfig;
42	  private vault: Vault;
43	  // Channels currently in "think deep" sticky mode (complex model)
44	  private complexModeChannels = new Set<string>();
45	  // Per-channel thinking level override (persists until changed or restart)
46	  private thinkingOverrides = new Map<string, "off" | "low" | "medium" | "high">();
47	
48	  constructor(config: MameConfig, persona: PersonaConfig, vault: Vault) {
49	    this.config = config;
50	    this.persona = persona;
51	    this.vault = vault;
52	    this.webhookServer = express();
53	    this.webhookServer.use(express.json({ limit: "100kb" })); // Limit request body size
54	  }
55	
56	  async start(): Promise<void> {
57	    if (this.config.discord?.enabled && this.persona.discord) {
58	      await this.startDiscord();
59	    }
60	    if (this.config.line?.enabled && this.persona.line) {
61	      await this.startLINE();
62	    }
63	    if (this.config.signal?.enabled && this.persona.signal) {
64	      await this.startSignal();
65	    }
66	    await this.startWebhooks();
67	    this.startTUI();
68	    // Note: "Mame is awake" log is emitted by index.ts after heartbeat.start()
69	  }
70	
71	  // --- Discord ---
72	  private async startDiscord(): Promise<void> {
73	    this.discord = new Client({
74	      intents: [
75	        GatewayIntentBits.Guilds,
76	        GatewayIntentBits.GuildMessages,
77	        GatewayIntentBits.MessageContent,
78	      ],
79	    });
80	
81	    this.discord.on("messageCreate", async (msg) => {
82	      if (msg.author.bot) return;
83	
84	      // Only respond in channels mapped to this persona
85	      const channelMap = this.persona.discord?.channelMap || {};
86	      if (!(msg.channelId in channelMap)) return;
87	
88	      const project = channelMap[msg.channelId] || undefined;
89	
90	      // Evening 6: if a child agent (Claude Code) is currently waiting
91	      // for an answer to a question it asked via ask_human, route this
92	      // message as the answer INSTEAD of running it through think().
93	      // The child agent's MCP tool call will resolve, its execution
94	      // continues, and the user gets a one-line acknowledgement so
95	      // they know the message went to the subprocess, not to Mame.
96	      if (hasPendingQuestion("discord", msg.channelId)) {
97	        const delivered = provideAnswer("discord", msg.channelId, msg.content);
98	        if (delivered) {
99	          await msg.channel.send(
100	            "📨 Forwarded your answer to the running task. I'll let you know when it's done."
101	          );
102	          return;
103	        }
104	      }
105	
106	      // Capture image attachments
107	      const imageUrls = msg.attachments
108	        .filter((a) => a.contentType?.startsWith("image/"))
109	        .map((a) => a.url);
110	
111	      // Download text file attachments and inline their content
112	      const textAttachments = msg.attachments.filter(
113	        (a) =>
114	          a.contentType?.startsWith("text/") ||
115	          a.name?.endsWith(".txt") ||
116	          a.name?.endsWith(".md") ||
117	          a.name?.endsWith(".csv") ||
118	          a.name?.endsWith(".json") ||
119	          a.name?.endsWith(".yml") ||
120	          a.name?.endsWith(".yaml") ||
121	          a.name?.endsWith(".xml") ||
122	          a.name?.endsWith(".log") ||
123	          a.name?.endsWith(".ts") ||
124	          a.name?.endsWith(".js") ||
125	          a.name?.endsWith(".py") ||
126	          a.name?.endsWith(".sh")
127	      );
128	
129	      let messageText = msg.content;
130	      for (const att of textAttachments.values()) {
131	        try {
132	          const res = await fetch(att.url);
133	          if (res.ok) {
134	            const text = await res.text();
135	            // Cap at 50KB to avoid flooding context
136	            const truncated =
137	              text.length > 50_000
138	                ? text.slice(0, 50_000) + "\n... (truncated, file was " + text.length + " chars)"
139	                : text;
140	            messageText += `\n\n--- Attached file: ${att.name} ---\n${truncated}\n--- End of ${att.name} ---`;
141	          }
142	        } catch (err) {
143	          log.warn({ file: att.name, err: String(err) }, "Failed to download text attachment");
144	        }
145	      }
146	
147	      // Show typing indicator while thinking (refreshes every 8s, Discord typing lasts 10s)
148	      await msg.channel.sendTyping();
149	      const typingInterval = setInterval(() => {
150	        msg.channel.sendTyping().catch(() => {});
151	      }, 8000);
152	
153	      try {
154	        // Model mode switching: "think deep" / "think normal"
155	        // Sticky per-channel — stays on complex until explicitly switched back
156	        const thinkDeepToggle = /^think\s+deep\s*$/i;
157	        const thinkDeepInline = /^think\s+deep\s*:\s*/i;
158	        const thinkNormal = /^think\s+(normal|fast|default)\s*$/i;
159	
160	        if (thinkNormal.test(messageText.trim())) {
161	          this.complexModeChannels.delete(msg.channelId);
162	          log.info({ channel: msg.channelId }, "Switched back to default model");
163	          await msg.channel.send("⚡ Back to default model.");
164	          clearInterval(typingInterval);
165	          return;
166	        }
167	
168	        if (thinkDeepToggle.test(messageText.trim()) && this.persona.models.complex) {
169	          this.complexModeChannels.add(msg.channelId);
170	          log.info({ channel: msg.channelId, model: this.persona.models.complex }, "Switched to complex model (sticky)");
171	          await msg.channel.send(`🧠 Switched to complex model. All messages in this channel use \`${this.persona.models.complex}\` until you say "think normal".`);
172	          clearInterval(typingInterval);
173	          return;
174	        }
175	
176	        // "think deep: <message>" — one-shot, also activates sticky mode
177	        if (thinkDeepInline.test(messageText) && this.persona.models.complex) {
178	          messageText = messageText.replace(thinkDeepInline, "");
179	          this.complexModeChannels.add(msg.channelId);
180	          log.info({ channel: msg.channelId, model: this.persona.models.complex }, "Switched to complex model (sticky, inline)");
181	        }
182	
183	        // Reasoning toggle: "reasoning on/off/low/medium/high"
184	        const reasoningMatch = messageText.trim().match(/^reasoning\s+(on|off|low|medium|high)\s*$/i);
185	        if (reasoningMatch) {
186	          const level = reasoningMatch[1].toLowerCase();
187	          if (level === "off") {
188	            this.thinkingOverrides.set(msg.channelId, "off");
189	            await msg.channel.send("🚫 Reasoning disabled. Faster & cheaper responses, but may be less thoughtful.");
190	          } else {
191	            const mapped = (level === "on" ? "medium" : level) as "low" | "medium" | "high";
192	            this.thinkingOverrides.set(msg.channelId, mapped);
193	            await msg.channel.send(`🧠 Reasoning set to **${mapped}**. Will think before responding.`);
194	          }
195	          log.info({ channel: msg.channelId, level }, "Reasoning level changed");
196	          clearInterval(typingInterval);
197	          return;
198	        }
199	
200	        // Resolve model: sticky complex mode > default
201	        const modelOverride = this.complexModeChannels.has(msg.channelId)
202	          ? this.persona.models.complex
203	          : undefined;
204	        const thinkingOverride = this.thinkingOverrides.get(msg.channelId);
205	
206	        const turn = this.buildTurn(messageText, "discord", project, modelOverride, thinkingOverride);
207	        if (imageUrls.length > 0) turn.imageUrls = imageUrls;
208	        const reply = await think(turn);
209	
210	        for (const chunk of splitMessage(reply, 2000)) {
211	          await msg.channel.send(chunk);
212	        }
213	      } finally {
214	        clearInterval(typingInterval);
215	      }
216	    });
217	
218	    const token = await this.vault.get("global", "DISCORD_BOT_TOKEN");
219	    if (!token) {
220	      log.error("DISCORD_BOT_TOKEN not found in vault — Discord will not start");
221	      return;
222	    }
223	    await this.discord.login(token);
224	    log.info({ user: this.discord.user?.tag }, `Discord connected as ${this.discord.user?.tag}`);
225	  }
226	
227	  // --- LINE (acknowledge-then-push pattern) ---
228	  private async startLINE(): Promise<void> {
229	    const channelAccessToken = await this.vault.get("global", "LINE_CHANNEL_ACCESS_TOKEN");
230	    const channelSecret = await this.vault.get("global", "LINE_CHANNEL_SECRET");
231	
232	    if (!channelAccessToken || !channelSecret) {
233	      log.error("LINE credentials not found in vault — LINE will not start");
234	      return;
235	    }
236	
237	    this.line = new messagingApi.MessagingApiClient({ channelAccessToken });
238	
239	    // LINE uses webhooks — register handler on the Express server
240	    this.webhookServer.post(
241	      "/line/webhook",
242	      middleware({ channelSecret }),
243	      async (req, res) => {
244	        res.status(200).end();
245	
246	        for (const event of req.body.events) {
247	          if (event.type !== "message" || event.message.type !== "text") continue;
248	
249	          const userId = event.source.userId;
250	
251	          // Only respond to mapped LINE users
252	          const lineUserIds = this.persona.line?.userIds || [];
253	          if (!lineUserIds.includes(userId)) continue;
254	
255	          const project = this.config.line?.userMap?.[userId] || undefined;
256	
257	          // Acknowledge immediately to use the free reply token
258	          try {
259	            await this.line!.replyMessage({
260	              replyToken: event.replyToken,
261	              messages: [{ type: "text", text: "🫘" }],
262	            });
263	          } catch {
264	            // Reply token may already be expired, that's fine
265	          }
266	
267	          // Process the message (may take >30s for complex tasks)
268	          const reply = await think(this.buildTurn(event.message.text, "line", project));
269	
270	          // Send the real response via pushMessage
271	          for (const chunk of splitMessage(reply, 5000)) {
272	            await this.line!.pushMessage({
273	              to: userId,
274	              messages: [{ type: "text", text: chunk }],
275	            });
276	          }
277	        }
278	      }
279	    );
280	
281	    log.info("LINE webhook registered at /line/webhook");
282	  }
283	
284	  // --- Signal ---
285	  private onboardingSessions = new Set<string>(); // Track active onboarding conversations
286	
287	  private async startSignal(): Promise<void> {
288	    const signalNumber = this.config.signal!.number;
289	    this.signal = new SignalClient(signalNumber);
290	
291	    // Queue for receiving messages during onboarding (per-user)
292	    const messageQueues = new Map<string, ((text: string) => void)[]>();
293	
294	    this.signal.on("message", async (msg: SignalMessage) => {
295	      // Skip group messages
296	      if (msg.groupId) return;
297	
298	      // If this user is in an active onboarding session, route to the queue
299	      if (this.onboardingSessions.has(msg.sender)) {
300	        const queue = messageQueues.get(msg.sender);
301	        if (queue && queue.length > 0) {
302	          const resolve = queue.shift()!;
303	          resolve(msg.text);
304	        }
305	        return;
306	      }
307	
308	      // Check if this is a known/mapped user
309	      const userNumbers = this.persona.signal?.userNumbers || [];
310	      const isKnownUser = userNumbers.includes(msg.sender);
311	      const globalUserMap = this.config.signal?.userMap || {};
312	      const isMappedUser = msg.sender in globalUserMap;
313	
314	      if (!isKnownUser && !isMappedUser) {
315	        // Unknown user — start onboarding
316	        log.info({ sender: msg.sender }, "Unknown Signal user — starting onboarding");
317	        this.onboardingSessions.add(msg.sender);
318	        messageQueues.set(msg.sender, []);
319	
320	        const sendFn = async (text: string) => {
321	          for (const chunk of splitMessage(text, 5000)) {
322	            await this.signal!.send(msg.sender, chunk);
323	          }
324	        };
325	
326	        const receiveFn = (): Promise<string> => {
327	          return new Promise((resolve) => {
328	            const queue = messageQueues.get(msg.sender)!;
329	            queue.push(resolve);
330	          });
331	        };
332	
333	        try {
334	          const model = process.env.MAME_ONBOARD_MODEL || "google/gemini-3.1-flash-lite-preview";
335	          await runSignalOnboarding(
336	            model,
337	            msg.sender,
338	            msg.text,
339	            signalNumber,
340	            sendFn,
341	            receiveFn,
342	          );
343	          log.info({ sender: msg.sender }, "Signal onboarding complete");
344	
345	          // Notify admin to restart for new persona to take effect
346	          await this.notify(undefined, `🫘 New persona onboarded via Signal: ${msg.sender}. Restart to activate: pm2 restart all`);
347	        } catch (err) {
348	          log.error({ sender: msg.sender, err: String(err) }, "Signal onboarding failed");
349	          await this.signal!.send(msg.sender, "Sorry, something went wrong during setup. Please try again.");
350	        } finally {
351	          this.onboardingSessions.delete(msg.sender);
352	          messageQueues.delete(msg.sender);
353	        }
354	        return;
355	      }
356	
357	      // Known user — normal conversation
358	      const project = globalUserMap[msg.sender] || undefined;
359	
360	      const reply = await think(this.buildTurn(msg.text, "signal", project));
361	
362	      for (const chunk of splitMessage(reply, 5000)) {
363	        await this.signal!.send(msg.sender, chunk);
364	      }
365	    });
366	
367	    await this.signal.start();
368	    log.info({ number: signalNumber }, `Signal connected as ${signalNumber}`);
369	  }
370	
371	  // --- Webhooks (New Relic, GitHub, AgentMail) ---
372	  private async startWebhooks(): Promise<void> {
373	    this.webhookServer.get("/health", (_req, res) => {
374	      res.json({ status: "ok", persona: this.persona.name, uptime: process.uptime() });
375	    });
376	
377	    // X OAuth 2.0 PKCE callback — browser lands here after user approves on twitter.com
378	    this.webhookServer.get("/x/callback", async (req, res) => {
379	      const { code, state, error } = req.query;
380	
381	      if (error) {
382	        res.status(400).send(`<html><body style="font-family:sans-serif;max-width:500px;margin:80px auto;text-align:center"><h2>❌ Auth denied</h2><p>${error}</p></body></html>`);
383	        return;
384	      }
385	
386	      const pending = readPendingAuth();
387	      if (!pending) {
388	        res.status(400).send(`<html><body style="font-family:sans-serif;max-width:500px;margin:80px auto;text-align:center"><h2>❌ No pending auth session</h2><p>Run <code>mame x auth</code> first.</p></body></html>`);
389	        return;
390	      }
391	
392	      if (state !== pending.state) {
393	        res.status(400).send(`<html><body style="font-family:sans-serif;max-width:500px;margin:80px auto;text-align:center"><h2>❌ State mismatch</h2><p>Possible CSRF. Run <code>mame x auth</code> again.</p></body></html>`);
394	        clearPendingAuth();
395	        return;
396	      }
397	
398	      try {
399	        const clientId = await this.vault.get("global", "X_CLIENT_ID");
400	        const clientSecret = await this.vault.get("global", "X_CLIENT_SECRET");
401	        if (!clientId || !clientSecret) {
402	          res.status(500).send(`<html><body style="font-family:sans-serif;max-width:500px;margin:80px auto;text-align:center"><h2>❌ Missing credentials</h2><p>X_CLIENT_ID or X_CLIENT_SECRET not in vault.</p></body></html>`);
403	          return;
404	        }
405	
406	        const tokens = await exchangeCodeForTokens(
407	          code as string,
408	          pending.verifier,
409	          clientId,
410	          clientSecret
411	        );
412	        await storeTokens(this.vault, tokens);
413	        clearPendingAuth();
414	        log.info("X OAuth 2.0 complete — tokens stored in vault");
415	
416	        res.send(`<!DOCTYPE html><html>
417	<head><title>X Auth Complete</title></head>
418	<body style="font-family:sans-serif;max-width:500px;margin:80px auto;text-align:center">
419	  <h1>✅ Connected to X</h1>
420	  <p>Mame can now access your bookmarks.</p>
421	  <p style="color:#666">You can close this tab.</p>
422	</body></html>`);
423	      } catch (err) {
424	        log.error({ err: String(err) }, "X callback: token exchange failed");
425	        res.status(500).send(`<html><body style="font-family:sans-serif;max-width:500px;margin:80px auto;text-align:center"><h2>❌ Token exchange failed</h2><p>${String(err)}</p></body></html>`);
426	      }
427	    });
428	
429	    this.webhookServer.post("/webhook/:source", async (req, res) => {
430	      const source = req.params.source;
431	      const message = `Incoming webhook from ${source}: ${JSON.stringify(req.body)}`;
432	      // TODO: parseWebhook and routeWebhookToProject per source
433	
434	      res.status(200).json({ received: true });
435	
436	      const reply = await think(this.buildTurn(message, "webhook"));
437	      await this.notify(undefined, reply);
438	    });
439	
440	    this.webhookServer.post("/webhook/test", async (req, res) => {
441	      const message = req.body.message || "Test webhook received";
442	      res.status(200).json({ received: true, message });
443	      await this.notify(undefined, `🔔 ${message}`);
444	    });
445	
446	    const port = this.config.webhook?.port || 3847;
447	    const host = process.env.MAME_BIND_HOST || "0.0.0.0";
448	    this.webhookServer.listen(port, host, () => {
449	      log.info({ host, port }, `Webhook server listening on ${host}:${port}`);
450	    }).on("error", (err: NodeJS.ErrnoException) => {
451	      if (err.code === "EADDRINUSE") {
452	        log.warn({ host, port }, `Webhook port ${port} already in use — skipping (another persona likely owns it)`);
453	      } else {
454	        throw err;
455	      }
456	    });
457	  }
458	
459	  // --- TUI (Terminal UI) ---
460	  private startTUI(): void {
461	    // Don't start TUI if stdin is not a TTY (e.g., running as daemon)
462	    if (!process.stdin.isTTY) return;
463	
464	    const rl = readline.createInterface({
465	      input: process.stdin,
466	      output: process.stdout,
467	    });
468	
469	    const prompt = (): void => {
470	      rl.question(`🫘 ${this.persona.name}> `, async (input) => {
471	        if (!input.trim()) {
472	          prompt();
473	          return;
474	        }
475	        if (input === "exit") process.exit(0);
476	
477	        // TUI commands
478	        if (input.startsWith("/")) {
479	          await this.handleTUICommand(input);
480	        } else {
481	          const reply = await think(this.buildTurn(input, "cli"));
482	          console.log(`\n${reply}\n`);
483	        }
484	        prompt();
485	      });
486	    };
487	
488	    prompt();
489	  }
490	
491	  private async handleTUICommand(input: string): Promise<void> {
492	    const [cmd, ...args] = input.slice(1).split(" ");
493	    switch (cmd) {
494	      case "status":
495	        console.log(JSON.stringify({
496	          persona: this.persona.name,
497	          uptime: process.uptime(),
498	          discord: this.discord?.isReady() || false,
499	          line: !!this.line,
500	          signal: !!this.signal,
501	        }, null, 2));
502	        break;
503	      case "memory": {
504	        const query = args.join(" ");
505	        if (!query) {
506	          const stats = await memoryStats();
507	          console.log(JSON.stringify(stats, null, 2));
508	        } else {
509	          const results = await recall(query);
510	          for (const r of results) {
511	            console.log(`[${r.id}] ${r.content}`);
512	          }
513	        }
514	        break;
515	      }
516	      case "heartbeat":
517	        console.log("Running heartbeat... (use the heartbeat scheduler for automated checks)");
518	        break;
519	      case "cost":
520	        console.log("Cost reporting not yet implemented");
521	        break;
522	      case "secrets": {
523	        const project = args[0] || "global";
524	        const keys = await this.vault.list(project);
525	        console.log(`Secrets for ${project}: ${keys.join(", ") || "(none)"}`);
526	        break;
527	      }
528	      case "doctor":
529	        console.log("Running health check...");
530	        console.log(`  Persona: ${this.persona.name}`);
531	        console.log(`  Discord: ${this.discord?.isReady() ? "✅ connected" : "❌ not connected"}`);
532	        console.log(`  LINE: ${this.line ? "✅ configured" : "❌ not configured"}`);
533	        console.log(`  Webhook: ✅ port ${this.config.webhook?.port || 3847}`);
534	        console.log(`  Memory: ✅ ${(await memoryStats()).total} memories`);
535	        break;
536	      case "help":
537	        console.log(`
538	  /status     — Show agent health
539	  /memory     — Search memories (or show stats with no query)
540	  /heartbeat  — Force heartbeat
541	  /cost       — API cost report
542	  /secrets    — List secret keys
543	  /doctor     — Full health check
544	  /help       — This message
545	        `);
546	        break;
547	      default:
548	        console.log(`Unknown command: /${cmd}. Type /help for commands.`);
549	    }
550	  }
551	
552	  // Send notification to user's preferred channel
553	  async notify(project: string | undefined, message: string): Promise<void> {
554	    // Try Discord first
555	    if (this.discord?.isReady()) {
556	      const channelMap = this.persona.discord?.channelMap || {};
557	      const channelId = project
558	        ? Object.entries(channelMap).find(([, p]) => p === project)?.[0]
559	        : this.config.discord?.defaultChannel;
560	
561	      if (channelId) {
562	        try {
563	          const channel = await this.discord.channels.fetch(channelId);
564	          if (channel && "send" in channel) {
565	            for (const chunk of splitMessage(message, 2000)) {
566	              await (channel as TextChannel).send(chunk);
567	            }
568	            return;
569	          }
570	        } catch (err) {
571	          log.error({ err: String(err) }, "Discord notify failed");
572	        }
573	      }
574	    }
575	
576	    // Fallback to Signal
577	    if (this.signal && this.config.signal?.userMap) {
578	      // Send to the first mapped user
579	      const firstUser = Object.keys(this.config.signal.userMap)[0];
580	      if (firstUser) {
581	        for (const chunk of splitMessage(message, 5000)) {
582	          await this.signal.send(firstUser, chunk);
583	        }
584	        return;
585	      }
586	    }
587	
588	    // Fallback to LINE
589	    if (this.line && this.config.line?.defaultUserId) {
590	      for (const chunk of splitMessage(message, 5000)) {
591	        await this.line.pushMessage({
592	          to: this.config.line.defaultUserId,
593	          messages: [{ type: "text", text: chunk }],
594	        });
595	      }
596	    }
597	  }
598	
599	  private buildTurn(
600	    message: string,
601	    channel: Turn["channel"],
602	    project?: string,
603	    modelOverride?: string,
604	    thinkingOverride?: Turn["thinkingLevel"]
605	  ): Turn {
606	    return {
607	      message,
608	      channel,
609	      project: project || undefined,
610	      personaId: this.persona.name,
611	      soulFile: this.persona.soul,
612	      model: modelOverride || this.persona.models.default,
613	      tools: this.persona.tools,
614	      thinkingLevel: thinkingOverride || this.persona.thinkingLevel,
615	    };
616	  }
617	}
