38	
39	const log = childLogger("magazine:digest");
40	
41	const MASTHEAD_TITLE = "dAIly digest";
42	const FROM_LOCATION = "Kamakura, Japan";
43	const SUMMARIZE_CONCURRENCY = 5;
44	const OLD_GOLD_TARGET = 5;
45	const OLD_GOLD_CANDIDATE_POOL = 20;
46	
47	// ---------------------------------------------------------------------------
48	// Locked data contract types — see tasks/daily-digest-handoff.md lines 60-111
49	// ---------------------------------------------------------------------------
50	
