196	      title: MASTHEAD_TITLE,
197	      dateRange: formatDateRange(date),
198	      fromLocation: FROM_LOCATION,
199	      runtime: formatRuntime(runtimeMs),
200	    },
201	    signal,
202	    sections,
203	    featured,
204	    rest,
205	    oldGold,
206	    stats: {
207	      savedToday: records.length,
208	      totalProcessed: archive.total,
209	      topCategory,
210	    },
211	  };
212	
213	  const outPath = issueJsonPath(date);
214	  fs.writeFileSync(outPath, JSON.stringify(issue, null, 2), "utf-8");
215	  log.info({ path: outPath, runtimeMs, items: records.length, oldGold: oldGold.length }, "digest written");
216	
217	  return { issue, path: outPath };
218	}
