220	// ---------------------------------------------------------------------------
221	// LLM helpers
222	// ---------------------------------------------------------------------------
223	
224	interface PiModel {
225	  api: unknown;
226	  provider: unknown;
227	  id: unknown;
228	  reasoning?: boolean;
229	}
230	
231	function resolveModel(persona: PersonaConfig): ReturnType<typeof getModel> {
232	  const modelString = persona.models.complex ?? persona.models.default;
233	  const route = parseModelString(modelString);
234	  // Cast through unknown — pi-ai's KnownProvider is a string-literal union we
235	  // don't enumerate here, and parseModelString already validates the prefix.
236	  const model = getModel(route.backend as unknown as KnownProvider, route.modelId as never);
237	  if (!model) throw new Error(`Model not found in pi-ai catalog: ${modelString}`);
238	  return model;
239	}
240	
241	function extractText(response: AssistantMessage): string {
242	  const parts: string[] = [];
243	  for (const block of response.content) {
244	    if (block.type === "text") parts.push(block.text);
245	  }
246	  return parts.join("\n").trim();
247	}
248	
249	/**
250	 * Lenient JSON extractor. In order:
251	 *   1. Strip leading/trailing whitespace.
252	 *   2. If a ```json…``` (or plain ```…```) fence appears anywhere, extract
253	 *      its inner content first.
254	 *   3. Trim everything before the first `{` or `[` and after the matching
255	 *      closing brace/bracket.
256	 *   4. JSON.parse.
257	 * Models love to wrap JSON in prose, headers, or "**JSON Output**" preambles.
258	 * This recovers from all of those.
259	 */
260	function parseJsonResponse<T>(raw: string, hint: string): T {
261	  let s = raw.trim();
262	
263	  const fence = s.match(/```(?:json)?\s*\n?([\s\S]*?)```/);
264	  if (fence) s = fence[1].trim();
265	
266	  const firstBrace = s.search(/[{[]/);
267	  if (firstBrace > 0) s = s.slice(firstBrace);
268	  const lastBrace = Math.max(s.lastIndexOf("}"), s.lastIndexOf("]"));
269	  if (lastBrace > 0 && lastBrace < s.length - 1) s = s.slice(0, lastBrace + 1);
270	
271	  try {
272	    return JSON.parse(s) as T;
273	  } catch (err) {
274	    log.error({ raw, hint }, "LLM returned malformed JSON");
275	    throw new Error(`Malformed JSON in ${hint}: ${err}`);
276	  }
277	}
278	
279	/**
280	 * Last-ditch parser for the {summary, whyItMatters} pair when the model
281	 * decides to emit markdown instead of JSON. Tolerates:
282	 *   **summary**: text     **whyItMatters**: text
283	 *   **Summary:** text     **Why It Matters:** text
284	 *   **SUMMARY**\ntext     **WHY IT MATTERS**\ntext
285	 *   ...etc. Returns null if neither field is recoverable.
286	 */
287	function parseMarkdownSummaryPair(
288	  raw: string
289	): { summary: string; whyItMatters: string } | null {
290	  const sumRe = /\*\*\s*summary\s*:?\s*\*\*\s*:?\s*\n?\s*([\s\S]*?)(?=\n?\s*\*\*\s*why|\n?\s*\*\*\s*whyitmatters|$)/i;
291	  const whyRe = /\*\*\s*(?:why\s*it\s*matters?|whyitmatters?)\s*:?\s*\*\*\s*:?\s*\n?\s*([\s\S]*?)$/i;
292	
293	  const sumMatch = raw.match(sumRe);
294	  const whyMatch = raw.match(whyRe);
295	  if (!sumMatch && !whyMatch) return null;
296	
297	  const summary = (sumMatch?.[1] ?? "").trim();
298	  const whyItMatters = (whyMatch?.[1] ?? "").trim();
299	  if (!summary && !whyItMatters) return null;
300	
301	  return {
302	    summary: summary || "(summary unavailable)",
303	    whyItMatters: whyItMatters || "(why-it-matters unavailable)",
304	  };
305	}
306	
307	async function llmJson<T>(
308	  piModel: ReturnType<typeof getModel>,
309	  systemPrompt: string,
310	  userPrompt: string,
311	  hint: string,
312	  maxTokens: number = 800
313	): Promise<T> {
314	  const ctx: Context = {
315	    systemPrompt,
316	    messages: [{ role: "user", content: [{ type: "text", text: userPrompt }], timestamp: Date.now() }],
317	  };
318	  const response = await completeSimple(piModel, ctx, { maxTokens });
319	  return parseJsonResponse<T>(extractText(response), hint);
320	}
321	
322	async function llmText(
323	  piModel: ReturnType<typeof getModel>,
324	  systemPrompt: string,
325	  userPrompt: string,
326	  maxTokens: number = 200
327	): Promise<string> {
328	  const ctx: Context = {
329	    systemPrompt,
330	    messages: [{ role: "user", content: [{ type: "text", text: userPrompt }], timestamp: Date.now() }],
331	  };
332	  const response = await completeSimple(piModel, ctx, { maxTokens });
333	  return extractText(response);
334	}
335	
336	// ---------------------------------------------------------------------------
337	// Step 1: per-item summarization
338	// ---------------------------------------------------------------------------
339	
340	interface SummarizedItem extends IngestRecord {
341	  summary: string;
342	  whyItMatters: string;
343	}
344	
345	const SUMMARIZE_SYSTEM = `You are an editor for Mike's daily personal intelligence magazine, "dAIly digest".
346	Mike is a builder: he ships AI-augmented developer tools, runs his own infra, makes daily editorial decisions about which tools and ideas are worth his attention. He saves things to X bookmarks throughout the day.
347	
348	Your job: write tight, specific, useful editorial copy for each bookmark. No hype, no marketing fluff, no "in today's fast-paced AI landscape" preambles.
349	
350	CRITICAL OUTPUT FORMAT — read carefully:
351	- Output ONLY a single JSON object. Nothing before it. Nothing after it.
352	- Do NOT use markdown bold (**), headers, "Summary:" labels, code fences, or any prose framing.
353	- Do NOT explain what you're doing. Just emit the JSON.
354	
355	Schema:
356	{
357	  "summary": "Two sentences. What is this thing? Be concrete and specific.",
358	  "whyItMatters": "One sentence. Why should Mike care? Tie it to his work building dev tools, AI-augmented workflows, or running his own systems."
359	}
360	
361	Example output (this is the EXACT format — nothing else):
362	{"summary":"Open-source CLI that wraps the Anthropic API with built-in prompt caching, streaming, and tool-use helpers. Single binary, no Node deps.","whyItMatters":"Drop-in replacement for the boilerplate Mike already writes around every Anthropic SDK call — saves hours per project."}`;
363	
364	async function summarizeItems(
365	  records: IngestRecord[],
366	  piModel: ReturnType<typeof getModel>
367	): Promise<SummarizedItem[]> {
368	  const results: SummarizedItem[] = new Array(records.length);
369	
370	  await mapWithConcurrency(
371	    records.map((r, idx) => ({ r, idx })),
372	    SUMMARIZE_CONCURRENCY,
373	    async ({ r, idx }) => {
374	      const userPrompt = buildItemPrompt(r);
375	      const ctx: Context = {
376	        systemPrompt: SUMMARIZE_SYSTEM,
377	        messages: [{ role: "user", content: [{ type: "text", text: userPrompt }], timestamp: Date.now() }],
378	      };
379	      let raw = "";
380	      try {
381	        const response = await completeSimple(piModel, ctx, { maxTokens: 400 });
382	        raw = extractText(response);
383	
384	        // Try strict JSON first.
385	        let parsed: { summary?: string; whyItMatters?: string };
386	        try {
387	          parsed = parseJsonResponse(raw, `summarize bookmark ${r.id}`);
388	        } catch {
389	          // Markdown fallback — recover content the model put in **bold** form.
390	          const md = parseMarkdownSummaryPair(raw);
391	          if (!md) throw new Error("neither JSON nor markdown pair found");
392	          log.debug({ id: r.id }, "recovered summary via markdown parser");
393	          parsed = md;
394	        }
395	
396	        results[idx] = {
397	          ...r,
398	          summary: parsed.summary ?? r.linkedTitle ?? r.text.slice(0, 200),
399	          whyItMatters: parsed.whyItMatters ?? "(why-it-matters unavailable)",
400	        };
401	      } catch (err) {
402	        log.warn({ id: r.id, err: String(err), raw: raw.slice(0, 300) }, "summarize failed — using fallback");
403	        results[idx] = {
404	          ...r,
405	          summary: r.linkedTitle ?? r.text.slice(0, 200),
406	          whyItMatters: "(summary unavailable)",
407	        };
408	      }
409	    }
410	  );
411	
412	  return results;
413	}
414	
415	function buildItemPrompt(r: IngestRecord): string {
416	  const lines: string[] = [];
417	  lines.push(`Bookmark folder: ${r.folder ?? "(unfiled)"}`);
418	  lines.push(`Saved: ${r.savedAt ?? "(unknown)"}`);
419	  lines.push(`Tweet text: ${r.text}`);
420	  if (r.linkedUrl) lines.push(`Linked URL: ${r.linkedUrl}`);
421	  if (r.linkedTitle) lines.push(`Link title: ${r.linkedTitle}`);
422	  if (r.linkedDescription) lines.push(`Link description: ${r.linkedDescription}`);
423	  if (r.articleExcerpt) {
424	    lines.push(`Article excerpt (first ~3000 chars):`);
425	    lines.push(r.articleExcerpt.slice(0, 3000));
426	  }
427	  return lines.join("\n");
428	}
429	
430	// ---------------------------------------------------------------------------
431	// Step 2: group into sections by folder
432	// ---------------------------------------------------------------------------
433	
434	function groupIntoSections(items: SummarizedItem[]): IssueSection[] {
435	  const byFolder = new Map<string, SummarizedItem[]>();
436	  for (const item of items) {
437	    const folder = item.folder ?? "Inbox";
438	    if (!byFolder.has(folder)) byFolder.set(folder, []);
439	    byFolder.get(folder)!.push(item);
440	  }
441	
442	  // Sort folders by item count desc, then alpha for stability
443	  const folders = [...byFolder.entries()].sort((a, b) => {
444	    if (b[1].length !== a[1].length) return b[1].length - a[1].length;
445	    return a[0].localeCompare(b[0]);
446	  });
447	
448	  return folders.map(([folder, sectionItems], i) => ({
449	    number: String(i + 1).padStart(2, "0"),
450	    slug: slugify(folder),
451	    title: folder,
452	    subtitle: "",
453	    items: sectionItems.map<IssueItem>((it) => ({
454	      id: it.id,
455	      source: "x",
456	      sourceUrl: it.sourceUrl,
457	      linkedUrl: it.linkedUrl,
458	      linkedTitle: it.linkedTitle,
459	      heroImage: it.heroImage,
460	      savedAt: it.savedAt,
461	      summary: it.summary,
462	      whyItMatters: it.whyItMatters,
463	      isOldGold: false,
464	    })),
465	  }));
466	}
467	
468	// ---------------------------------------------------------------------------
469	// Step 3: Old Gold
470	// ---------------------------------------------------------------------------
471	
472	const OLD_GOLD_SYSTEM = `You curate "Old Gold" — older bookmarks from Mike's archive that are worth resurfacing today because they thematically tie to today's drift.
473	
474	Pick exactly ${OLD_GOLD_TARGET} candidates with the strongest thematic overlap. For each, write a one-sentence resurfaceReason explaining the connection — be specific about what links the old item to today's themes.
475	
476	Output STRICT JSON only — no prose around it, no markdown fences. Schema:
477	[
478	  { "id": "string", "resurfaceReason": "One sentence connecting this old bookmark to today's themes." }
479	]`;
480	
481	async function pickAndExplainOldGold(
482	  records: IngestRecord[],
483	  summarized: SummarizedItem[],
484	  piModel: ReturnType<typeof getModel>
485	): Promise<IssueOldGold[]> {
486	  const state = loadState();
487	  const todayIds = records.map((r) => r.id);
488	  const candidates = pickOldGoldCandidates(todayIds, state.oldGoldResurfaceLog, OLD_GOLD_CANDIDATE_POOL);
489	
490	  if (candidates.length === 0) {
491	    log.info("no Old Gold candidates available — archive may be too small or fully recently-resurfaced");
492	    return [];
493	  }
494	
495	  // Build today's themes from the summaries
496	  const themes = summarized
497	    .slice(0, 10)
498	    .map((s) => `- ${s.linkedTitle ?? s.text.slice(0, 80)} → ${s.summary}`)
499	    .join("\n");
500	
501	  const candidateLines = candidates
502	    .map(
503	      (c, i) =>
504	        `${i + 1}. id=${c.id} | folder=${c.folder ?? "(unfiled)"} | saved=${c.saved_at} | title=${c.linked_title ?? "(none)"} | text=${c.text.slice(0, 200)}`
505	    )
506	    .join("\n");
507	
508	  const userPrompt = `Today's themes (from today's bookmarks):
509	${themes}
510	
511	Candidate older bookmarks (saved 30+ days ago, not recently resurfaced):
512	${candidateLines}
513	
514	Pick exactly ${OLD_GOLD_TARGET} with the strongest thematic ties to today.`;
515	
516	  let picks: Array<{ id: string; resurfaceReason: string }>;
517	  try {
518	    picks = await llmJson(piModel, OLD_GOLD_SYSTEM, userPrompt, "old gold pick", 1200);
519	  } catch (err) {
520	    log.warn({ err: String(err) }, "Old Gold LLM call failed — returning empty");
521	    return [];
522	  }
523	
524	  const candidatesById = new Map(candidates.map((c) => [c.id, c]));
525	  const today = new Date();
526	
527	  const out: IssueOldGold[] = [];
528	  for (const pick of picks.slice(0, OLD_GOLD_TARGET)) {
529	    const c = candidatesById.get(pick.id);
530	    if (!c) {
531	      log.warn({ id: pick.id }, "LLM picked an Old Gold id that wasn't in the candidate pool — skipping");
532	      continue;
533	    }
534	    const daysSince = c.saved_at
535	      ? Math.floor((today.getTime() - new Date(c.saved_at).getTime()) / 86400_000)
536	      : 0;
537	    out.push({
538	      id: c.id,
539	      source: "x",
540	      sourceUrl: c.source_url,
541	      linkedUrl: c.linked_url,
542	      linkedTitle: c.linked_title,
543	      heroImage: c.hero_image,
544	      savedAt: c.saved_at,
545	      summary: oldGoldSummary(c),
546	      resurfaceReason: pick.resurfaceReason,
547	      daysSinceSaved: daysSince,
548	    });
549	  }
550	  return out;
551	}
552	
553	function oldGoldSummary(c: ArchivedBookmark): string {
554	  if (c.linked_description) return c.linked_description.slice(0, 240);
555	  if (c.linked_title) return c.linked_title;
556	  return c.text.slice(0, 240);
557	}
558	
559	// ---------------------------------------------------------------------------
560	// Step 4: signal headline
561	// ---------------------------------------------------------------------------
562	
563	const SIGNAL_SYSTEM = `You write one-line editorial headlines for "dAIly digest", a daily personal intelligence magazine.
564	
565	Capture the day's drift in a single line under 80 characters. No quotes. No preamble. No "today we cover...". Editorial voice: dry, observational, specific. Think New Yorker contents page, not BuzzFeed.
566	
567	Output ONLY the headline. No JSON. No markdown.`;
568	
569	async function generateSignal(
570	  summarized: SummarizedItem[],
571	  piModel: ReturnType<typeof getModel>
572	): Promise<string> {
573	  const items = summarized
574	    .slice(0, 12)
575	    .map((s) => `- [${s.folder ?? "unfiled"}] ${s.linkedTitle ?? s.text.slice(0, 100)}`)
576	    .join("\n");
577	
578	  const userPrompt = `Today's items:
579	${items}
580	
581	Write the signal headline.`;
582	
583	  try {
584	    const text = await llmText(piModel, SIGNAL_SYSTEM, userPrompt, 100);
585	    return text.replace(/^["']|["']$/g, "").trim().slice(0, 200);
586	  } catch (err) {
587	    log.warn({ err: String(err) }, "Signal LLM call failed — using fallback");
588	    return "Today's drift.";
589	  }
590	}
591	
592	// ---------------------------------------------------------------------------
593	// Misc
594	// ---------------------------------------------------------------------------
595	
596	function loadRawJsonl(date: string): IngestRecord[] {
597	  const file = rawJsonlPath(date);
598	  if (!fs.existsSync(file)) return [];
599	  const raw = fs.readFileSync(file, "utf-8");
600	  const lines = raw.split("\n").filter((l) => l.trim().length > 0);
601	  return lines.map((l) => JSON.parse(l) as IngestRecord);
602	}
603	
604	function slugify(s: string): string {
605	  return s.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "").slice(0, 60);
606	}
607	
608	function formatDateRange(isoDate: string): string {
609	  const [y, m, d] = isoDate.split("-").map(Number);
610	  const date = new Date(Date.UTC(y, m - 1, d));
611	  return new Intl.DateTimeFormat("en-US", {
612	    month: "long",
613	    day: "numeric",
614	    year: "numeric",
615	    timeZone: "UTC",
616	  }).format(date);
617	}
618	
619	function formatRuntime(ms: number): string {
620	  const totalSec = Math.floor(ms / 1000);
621	  const h = String(Math.floor(totalSec / 3600)).padStart(2, "0");
622	  const m = String(Math.floor((totalSec % 3600) / 60)).padStart(2, "0");
623	  const s = String(totalSec % 60).padStart(2, "0");
624	  return `${h}:${m}:${s}`;
625	}
626	
627	async function mapWithConcurrency<T>(
628	  items: T[],
629	  concurrency: number,
630	  worker: (item: T) => Promise<void>
631	): Promise<void> {
632	  const queue = [...items];
633	  const runners: Promise<void>[] = [];
634	  for (let i = 0; i < Math.min(concurrency, queue.length); i++) {
635	    runners.push(
636	      (async () => {
637	        while (queue.length > 0) {
638	          const next = queue.shift();
639	          if (next === undefined) return;
640	          await worker(next);
641	        }
642	      })()
643	    );
644	  }
645	  await Promise.all(runners);
646	}
